import{_ as s,o as a,c as i,a2 as n}from"./chunks/framework.BflysNKA.js";const b=JSON.parse('{"title":"macOS 平台安装 Node.js","description":"","frontmatter":{},"headers":[],"relativePath":"node/macos.md","filePath":"node/macos.md","lastUpdated":1778663407000}'),p={name:"node/macos.md"};function l(t,e,r,d,o,h){return a(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="macos-平台安装-node-js" tabindex="-1">macOS 平台安装 Node.js <a class="header-anchor" href="#macos-平台安装-node-js" aria-label="Permalink to &quot;macOS 平台安装 Node.js&quot;">​</a></h1><p>推荐安装 Node.js LTS。常见做法是 Homebrew 或官方安装包。</p><p>完整 CLI 接入流程见 <a href="/beginner/macos">macOS 快速接入</a>。</p><p>安装 Node.js 的目标是让系统拥有 <code>node</code> 和 <code>npm</code> 两个命令。<code>node</code> 用来运行 JavaScript CLI，<code>npm</code> 用来下载和更新 Claude Code、Codex、Gemini CLI 等工具。</p><p>后面准备装的是 Codex、Gemini CLI、OpenCode 或其他 npm CLI 时，这一层基本迟早都要准备。<br> 先把 Node.js 装稳，后面很多“装包失败”“版本太旧”“命令找不到”的问题都会少很多。</p><h2 id="方法一-homebrew-推荐" tabindex="-1">方法一：Homebrew（推荐） <a class="header-anchor" href="#方法一-homebrew-推荐" aria-label="Permalink to &quot;方法一：Homebrew（推荐）&quot;">​</a></h2><p>Homebrew 会把 Node.js 安装到用户常用的命令路径里，后续升级和卸载都比较清楚。已经安装 Homebrew 的用户，优先使用这种方式。</p><p>第一次常见的犹豫是：“Homebrew 和 <code>.pkg</code> 到底选哪个？”<br> 已经在用 Homebrew 管理命令行工具时，优先继续用 Homebrew；只是想先快速装上 <code>node</code> 和 <code>npm</code> 时，图形安装包也完全可以。</p><p>更重要的一点不是“哪种方式更高级”，而是<strong>先固定一种方式装好，不要同一台机器上来回混装太多套 Node.js</strong>。<br> 混装本身不会立刻报错，但后面 <code>which node</code> 指到哪个路径、升级时改了哪一个版本，就会越来越难判断。</p><p>已经装了 Homebrew，直接执行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> node</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>验证：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -v</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">npm</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -v</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Homebrew 首次安装或更新很慢时，先换国内镜像源，再回来安装 Node.js。常用镜像帮助页：</p><ul><li>清华 Homebrew 镜像：<a href="https://mirrors.tuna.tsinghua.edu.cn/help/homebrew/" target="_blank" rel="noreferrer">https://mirrors.tuna.tsinghua.edu.cn/help/homebrew/</a></li><li>中科大 Homebrew 镜像：<a href="https://mirrors.ustc.edu.cn/help/brew.git.html" target="_blank" rel="noreferrer">https://mirrors.ustc.edu.cn/help/brew.git.html</a></li></ul><h2 id="方法二-浏览器下载安装包" tabindex="-1">方法二：浏览器下载安装包 <a class="header-anchor" href="#方法二-浏览器下载安装包" aria-label="Permalink to &quot;方法二：浏览器下载安装包&quot;">​</a></h2><p>不使用 Homebrew 时，可以直接安装 <code>.pkg</code>。这种方式更接近普通软件安装流程，适合只想先把 <code>node</code> 和 <code>npm</code> 跑起来的用户。</p><p>浏览器下载安装时，国内用户可以按这个顺序选：</p><ol><li>Node.js 中文站：<a href="https://nodejs.cn/download" target="_blank" rel="noreferrer">https://nodejs.cn/download</a></li><li>Node.js 镜像归档：<a href="https://npmmirror.com/mirrors/node/" target="_blank" rel="noreferrer">https://npmmirror.com/mirrors/node/</a></li><li>Node.js 英文官网：<a href="https://nodejs.org/en/download" target="_blank" rel="noreferrer">https://nodejs.org/en/download</a></li></ol><p>第一次安装优先打开 Node.js 中文站。页面是中文，能直接看到 macOS 安装包和架构选项。</p><p>第一次如果看到 Current、LTS 两种版本，优先选 <strong>LTS</strong>。<br> LTS 更适合日常 CLI 使用，后面安装各种工具时兼容性通常更稳。</p><p>常用选择：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>macOS 安装包 (.pkg) -&gt; Apple Silicon 选 ARM64，Intel 选 x64</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>下载后按提示完成安装，重新打开终端验证版本。</p><p>使用镜像归档时：</p><p>选择最新 LTS 版本目录：</p><ul><li>Apple 芯片：优先选择 <code>darwin-arm64</code></li><li>Intel 芯片：选择 <code>darwin-x64</code></li><li>不确定芯片：点左上角苹果图标，查看“关于本机”</li></ul><p>图形安装优先选择 <code>.pkg</code> 安装包；压缩包适合熟悉 PATH 配置的用户。</p><p>只是想先把环境跑通时，不建议第一次就选纯压缩包手动配 PATH。<br><code>.pkg</code> 更接近普通软件安装流程，变量和命令路径通常也更省心。</p><h2 id="安装-git" tabindex="-1">安装 Git <a class="header-anchor" href="#安装-git" aria-label="Permalink to &quot;安装 Git&quot;">​</a></h2><p>Claude Code、Codex 处理项目时会读取 Git 仓库状态、查看差异和识别当前工作目录。macOS 可以通过 Apple 命令行工具安装 Git。</p><p>安装方式建议按这个顺序选：</p><ol><li>Apple 命令行工具</li><li>Homebrew</li><li>Git 官网下载页</li></ol><p>只是想先把 <code>git</code> 命令装上时，优先直接安装 Apple 命令行工具：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">xcode-select</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --install</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>安装后验证：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">git</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>已经在用 Homebrew，也可以：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> git</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>浏览器下载入口：</p><ul><li>Git 官网：<a href="https://git-scm.com/download/mac" target="_blank" rel="noreferrer">https://git-scm.com/download/mac</a></li></ul><p>想用图形安装包时，再走官网页面。</p><p>Git 装好后，Claude Code、Codex 读取项目仓库会更稳定。</p><p>只看“能不能发一条模型请求”时，Git 似乎不像 Node.js 那么显眼。<br> 但只要后面要让 Claude Code、Codex 真正进入项目目录读代码、看差异、处理提交，Git 基本就是这类工具理解仓库状态的基础。</p><h2 id="配置-npm-镜像" tabindex="-1">配置 npm 镜像 <a class="header-anchor" href="#配置-npm-镜像" aria-label="Permalink to &quot;配置 npm 镜像&quot;">​</a></h2><p>npm 默认从官方 registry 下载依赖，国内网络下可能很慢。切到 npmmirror 后，安装 CLI 工具通常更快、更稳定。</p><p>这个设置只影响 npm 下载依赖，不会改变 小蓝中转站 的接口地址，也不会影响模型请求。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> registry</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> https://registry.npmmirror.com</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> registry</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>输出 <code>https://registry.npmmirror.com/</code> 即可。</p><p>这个设置只影响 npm 下载依赖，不会改变 小蓝中转站 的 Base URL，也不会影响你后面配置的 Key 和模型。<br> 很多新手第一次改镜像时会担心“是不是把模型请求也改走镜像了”，这里可以放心分开看：npm 镜像只影响安装层。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="homebrew-很慢" tabindex="-1">Homebrew 很慢 <a class="header-anchor" href="#homebrew-很慢" aria-label="Permalink to &quot;Homebrew 很慢&quot;">​</a></h3><p>先确认 Homebrew 本身能正常更新；必要时换镜像源后再安装。</p><h3 id="权限问题" tabindex="-1">权限问题 <a class="header-anchor" href="#权限问题" aria-label="Permalink to &quot;权限问题&quot;">​</a></h3><p>不要把 npm 全局目录改到系统目录。优先使用 Homebrew，或使用 nvm 管理 Node.js 版本。</p><p>如果全局安装 CLI 时出现 <code>EACCES</code>，不要直接加 <code>sudo</code>。先看 npm 全局目录：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> prefix</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>通过 Homebrew 安装的 Node.js 通常不会遇到这个问题。</p><p>浏览器安装 Node.js 的机器，安装全局 CLI 时更常见的处理方式是：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> npm</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> 包名</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>终端出现钥匙图标或 <code>Password:</code> 提示后，密码不会显示任何字符，也不会出现 <code>*</code>，直接输入完成后按回车即可。</p><h3 id="明明装过了-终端里还是旧版本" tabindex="-1">明明装过了，终端里还是旧版本 <a class="header-anchor" href="#明明装过了-终端里还是旧版本" aria-label="Permalink to &quot;明明装过了，终端里还是旧版本&quot;">​</a></h3><p>这通常说明你机器里可能已经存在另一套 Node.js。</p><p>先看：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">which</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> node</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -v</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>如果 <code>which node</code> 指向的不是你刚安装的那一套路径，后面装 CLI 时就可能继续沿用旧版本。<br> 这种时候先把“当前到底在用哪一套 Node.js”弄清楚，会比急着重装更有效。</p><h3 id="命令找不到" tabindex="-1">命令找不到 <a class="header-anchor" href="#命令找不到" aria-label="Permalink to &quot;命令找不到&quot;">​</a></h3><p>先开一个新的终端窗口，再执行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">which</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> node</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">which</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> npm</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">which</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> git</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>如果 <code>node</code> 查不到，重新安装 Node.js。 如果 <code>git</code> 查不到，先执行 <code>xcode-select --install</code>。</p><h3 id="homebrew-装了-浏览器安装包也装了-会不会冲突" tabindex="-1">Homebrew 装了，浏览器安装包也装了，会不会冲突 <a class="header-anchor" href="#homebrew-装了-浏览器安装包也装了-会不会冲突" aria-label="Permalink to &quot;Homebrew 装了，浏览器安装包也装了，会不会冲突&quot;">​</a></h3><p>不一定立刻冲突，但长期来看更容易把版本和路径搞乱。<br> 已经决定长期用 Homebrew 管命令行工具时，后面尽量继续用 Homebrew；已经用 <code>.pkg</code> 装稳时，也可以先保持这一套不动。</p><h3 id="zsh-和-bash-怎么选" tabindex="-1">zsh 和 bash 怎么选 <a class="header-anchor" href="#zsh-和-bash-怎么选" aria-label="Permalink to &quot;zsh 和 bash 怎么选&quot;">​</a></h3><p>新版本 macOS 默认是 zsh。本文里的持久化配置优先写入 <code>~/.zshrc</code>。使用 bash 时，再写入 <code>~/.bashrc</code> 或 <code>~/.bash_profile</code>。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/deploy/claude-code">Claude Code 部署</a></li><li><a href="/deploy/codex">Codex 部署</a></li><li><a href="/deploy/gemini-cli">Gemini CLI 部署</a></li></ul>`,76)])])}const m=s(p,[["render",l]]);export{b as __pageData,m as default};
